import Anthropic from '@anthropic-ai/sdk';
import { providerService } from './providerService';

// Initialize server-side only Anthropic client
const getAnthropicClient = () => {
  return new Anthropic({
    apiKey: process.env.ANTHROPIC_API_KEY || 'dummy_key', // Handled via env
  });
};

export interface ParsedJobIntent {
  service_category: string | null;
  location: string | null;
  urgency: 'low' | 'medium' | 'high';
  estimated_budget: string | null;
  reasoning: string;
}

export interface AIRankedProvider {
  provider_id: string;
  display_name: string;
  match_score: number; // 0-100 indicating AI's confidence in fit
  reasoning: string; // Explaining why the AI chose this provider
}

export const aiMatchingService = {
  /**
   * Natural Language Parsing: Transforms "I need a plumber in Lekki..." into structured filters
   */
  async parseUserIntent(prompt: string): Promise<ParsedJobIntent> {
    const anthropic = getAnthropicClient();

    const request = `
      You are an AI Assistant for "ServiceBridge", a local services marketplace.
      Extract structured data from the following customer request.

      Customer Request: "${prompt}"

      Output MUST be exactly valid JSON, obeying this schema:
      {
        "service_category": "Standardized category string like 'Plumber', 'Electrician', 'Cleaner', or null if unclear",
        "location": "City or neighborhood name, or null",
        "urgency": "low", "medium", or "high",
        "estimated_budget": "Extracted budget constraint or null",
        "reasoning": "One sentence explaining logic."
      }
    `;

    try {
      const response = await anthropic.messages.create({
        model: 'claude-3-5-sonnet-20241022',
        max_tokens: 300,
        temperature: 0,
        messages: [{ role: 'user', content: request }]
      });

      // Anthropic format output mapping
      const textBlock = response.content.find(c => c.type === 'text');
      const text = textBlock?.type === 'text' ? textBlock.text : '';

      // Parse out JSON
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (!jsonMatch) throw new Error('AI returned malformed JSON');

      return JSON.parse(jsonMatch[0]) as ParsedJobIntent;

    } catch (error) {
      console.error('AI Intent Parsing Failed:', error);
      // Fallback
      return { service_category: null, location: null, urgency: 'medium', estimated_budget: null, reasoning: 'Fallback executed.' };
    }
  },

  /**
   * AI Provider Ranking: Takes database candidates and applies a LLM heuristic match
   */
  async rankProvidersForJob(intent: ParsedJobIntent, rawProviders: any[]): Promise<AIRankedProvider[]> {
    if (rawProviders.length === 0) return [];

    // Safety subset constraint
    const candidates = rawProviders.slice(0, 10).map(p => ({
      id: p.id,
      name: p.display_name,
      rating: p.avg_rating,
      jobs: p.completed_jobs,
      trust_score: p.trust_score,
      rate: p.hourly_rate,
      location: p.service_area
    }));

    const anthropic = getAnthropicClient();

    const request = `
      You are the ranking engine for "ServiceBridge". 
      Rank these provider candidates based on the customer's intent.

      Intent:
      Category: ${intent.service_category}
      Location: ${intent.location}
      Urgency: ${intent.urgency}

      Candidates:
      ${JSON.stringify(candidates, null, 2)}

      Return valid JSON matching this schema:
      {
        "rankings": [
          {
            "provider_id": "string",
            "match_score": number (0-100),
            "reasoning": "Short sentence justifying rank based on proximity, trust_score, rating, and rate."
          }
        ]
      }
    `;

    try {
      const response = await anthropic.messages.create({
        model: 'claude-3-sonnet-20240229', // We can use HAIKU/SONNET for speed/cost
        max_tokens: 500,
        temperature: 0,
        messages: [{ role: 'user', content: request }]
      });

      const textBlock = response.content.find(c => c.type === 'text');
      const text = textBlock?.type === 'text' ? textBlock.text : '';
      const jsonMatch = text.match(/\{[\s\S]*\}/);

      if (!jsonMatch) throw new Error('AI ranking malformed');
      const parsed = JSON.parse(jsonMatch[0]);

      // Re-map back names to the output for ease of UI
      return parsed.rankings.map((r: any) => {
         const p = candidates.find(c => c.id === r.provider_id);
         return { ...r, display_name: p?.name || 'Unknown' };
      });

    } catch (error) {
      console.error('AI Ranking Engine Failed:', error);
      return [];
    }
  },

  /**
   * Generates a structural booking recommendation context
   */
  generateSuggestedBooking(intent: ParsedJobIntent, topProvider: any) {
    if (!topProvider) return null;

    let hoursEstimate = intent.urgency === 'high' ? 2 : 4;
    let cost = hoursEstimate * topProvider.hourly_rate;

    return {
      provider: topProvider,
      suggestion_note: `Based on your request, ${topProvider.display_name} is the best match in ${intent.location || 'your area'}. Highly rated (${topProvider.avg_rating} ⭐) with a trust score of ${topProvider.trust_score}.`,
      estimated_price: cost,
      estimated_hours: hoursEstimate
    };
  }
};

import posthog from 'posthog-js';

// Environment variable safety
const POSTHOG_KEY = process.env.NEXT_PUBLIC_POSTHOG_KEY || '';
const POSTHOG_HOST = process.env.NEXT_PUBLIC_POSTHOG_HOST || 'https://app.posthog.com';

export const analyticsService = {
  /**
   * Initialize PostHog (Must be called in the root layout or provider for client-side tracking)
   */
  init() {
    if (typeof window !== 'undefined' && POSTHOG_KEY) {
      posthog.init(POSTHOG_KEY, {
        api_host: POSTHOG_HOST,
        capture_pageview: false, // We handle this manually in Next.js 13/14+ App Router
        autocapture: false, // We prefer explicit telemetry for ServiceBridge
      });
    }
  },

  /**
   * Identify a user to tie operations back to their customer/provider profiles
   */
  identifyUser(clerkId: string, email: string, role: string) {
    if (typeof window !== 'undefined' && POSTHOG_KEY) {
      posthog.identify(clerkId, {
        email: email,
        role: role, // 'customer', 'provider', 'admin'
      });
    }
  },

  /**
   * Tracks a specific lifecycle event with attached metadata.
   */
  trackEvent(eventName: string, properties: Record<string, any> = {}) {
    if (typeof window !== 'undefined' && POSTHOG_KEY) {
      posthog.capture(eventName, {
        ...properties,
        timestamp: new Date().toISOString()
      });
    }
  },

  /**
   * Funnel Tracking: Standardizes the booking lifecycle path markers
   */
  trackBookingFunnel(stage: 'search' | 'provider_view' | 'booking_created' | 'payment_successful' | 'booking_started' | 'booking_completed', properties: Record<string, any> = {}) {
    this.trackEvent(`funnel_${stage}`, properties);
  },

  /**
   * Error Telemetry: Safely logs execution or state-machine failures
   */
  trackError(context: string, errorMsg: string, properties: Record<string, any> = {}) {
    this.trackEvent('system_error', {
      context,
      error_message: errorMsg,
      ...properties
    });
  }
};

import { createClient } from '@/lib/supabase/client';
import { Message, MessageType } from '@/types';

type SendMessageParams = Omit<Message, 'id' | 'created_at'>;

export const messagingService = {
  /**
   * Send a Text or Image Message
   */
  async sendMessage(params: SendMessageParams): Promise<Message> {
    const supabase = createClient();

    // Safety check: ensure booking_id exists
    if (!params.booking_id) throw new Error('Booking ID is required to send a message');

    const { data, error } = await supabase
      .from('messages')
      .insert({
        booking_id: params.booking_id,
        sender_id: params.sender_id,
        message_content: params.message_content,
        message_type: params.message_type
      })
      .select('*, users(name)')
      .single();

    if (error) throw error;

    // We would trigger a notification hook here for Phase 7
    return data as Message;
  },

  /**
   * Automated System Messaging (Invoked during Booking Lifecycle state changes)
   */
  async sendSystemMessage(bookingId: string, content: string): Promise<Message> {
    return this.sendMessage({
      booking_id: bookingId,
      message_content: content,
      message_type: 'system',
      // sender_id is intentionally blank for system broadcasts
    });
  },

  /**
   * Fetch paginated history
   */
  async getMessagesForBooking(bookingId: string, page = 1, limit = 50): Promise<Message[]> {
    const supabase = createClient();
    const from = (page - 1) * limit;
    const to = from + limit - 1;

    const { data, error } = await supabase
      .from('messages')
      .select('*, users(name)')
      .eq('booking_id', bookingId)
      .order('created_at', { ascending: false }) // typically fetched descending, then reversed in UI
      .range(from, to);

    if (error) throw error;
    return data as Message[];
  },

  /**
   * Subscribe to Supabase Realtime Channel exclusively bound to this booking
   */
  subscribeToBookingChannel(bookingId: string, callback: (payload: any) => void) {
    const supabase = createClient();

    // Create dedicated channel unique to this booking's chat
    const channel = supabase.channel(`booking:${bookingId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'messages',
          filter: `booking_id=eq.${bookingId}`
        },
        (payload) => {
          callback(payload.new);
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  },

  /**
   * Attachments via Supabase Storage
   */
  async uploadMessageAttachment(bookingId: string, file: File): Promise<string> {
    const supabase = createClient();
    const fileExt = file.name.split('.').pop();
    const fileName = `${bookingId}/${Math.random().toString(36).substring(2)}.${fileExt}`;

    const { data, error } = await supabase.storage
      .from('chat-attachments')
      .upload(fileName, file, { cacheControl: '3600' });

    if (error) throw error;

    // Use signed URLs for privacy or pass the path.
    // Given the requirement is secure access policies, we should create a signed URL logically,
    // or public URLs if the bucket isn't tightly locked per file.
    // For simplicity, we create a temporary signed URL valid for 1 year, or just store the path
    // and let the UI request signed URLs. Here we create an initial signed URL to embed.
    const { data: signData, error: signError } = await supabase.storage
      .from('chat-attachments')
      .createSignedUrl(fileName, 60 * 60 * 24 * 365); // 1 year

    if (signError || !signData) throw new Error('Signed URL creation failed');
    return signData.signedUrl;
  }
};

import { createClient } from '@/lib/supabase/client';
import { PaymentStatus, Payment } from '@/types';

// In Server Components/Actions, we'll instantiate our own headers.
const PAYSTACK_SECRET = process.env.PAYSTACK_SECRET_KEY as string;

export const paymentService = {
  /**
   * Initialize Escobar (Escrow) Payment Link for Customer
   */
  async initializePayment(bookingId: string, customerEmail: string, amount: number) {
    // 1. Hit Paystack API to generate checkout link
    const response = await fetch('https://api.paystack.co/transaction/initialize', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${PAYSTACK_SECRET}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        email: customerEmail,
        amount: amount * 100, // Kobo
        metadata: { booking_id: bookingId },
        callback_url: `${process.env.NEXT_PUBLIC_APP_URL}/customer/dashboard`,
      }),
    });

    const data = await response.json();
    if (!data.status) throw new Error(data.message);

    // 2. We do NOT create the payment record here. We wait for the webhook,
    // or we create it as 'initialized' to track intent.
    const supabase = createClient();
    const { data: booking } = await supabase.from('bookings').select('customer_id, provider_id').eq('id', bookingId).single();

    if (booking) {
      await supabase.from('payments').insert({
        booking_id: bookingId,
        customer_id: booking.customer_id,
        provider_id: booking.provider_id,
        amount: amount,
        paystack_reference: data.data.reference,
        payment_status: 'initialized',
      });
    }

    return data.data.authorization_url; // Send user here
  },

  /**
   * Verify Payment (Server-Side verification, bypasses client entirely)
   */
  async verifyPayment(reference: string) {
    const response = await fetch(`https://api.paystack.co/transaction/verify/${reference}`, {
      headers: {
        Authorization: `Bearer ${PAYSTACK_SECRET}`,
      },
    });

    const data = await response.json();
    return data;
  },

  /**
   * Creates a Paystack Transfer Recipient for the Provider
   */
  async createTransferRecipient(name: string, accountNumber: string, bankCode: string) {
    const response = await fetch('https://api.paystack.co/transferrecipient', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${PAYSTACK_SECRET}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        type: 'nuban',
        name,
        account_number: accountNumber,
        bank_code: bankCode,
        currency: 'NGN',
      }),
    });

    const data = await response.json();
    if (!data.status) throw new Error('Failed to create transfer recipient');
    return data.data.recipient_code;
  },

  /**
   * Disburse Escrow Funds to Provider via Paystack Transfer API
   */
  async releaseEscrow(bookingId: string) {
    const supabase = createClient();

    // 1. Validate Booking is COMPLETED and Escrow not already released
    const { data: booking, error } = await supabase
      .from('bookings')
      .select('*, providers(paystack_recipient_code), payments!inner(amount, paystack_reference)')
      .eq('id', bookingId)
      .single();

    if (error || !booking) throw new Error('Booking not found');
    if (booking.status !== 'COMPLETED') throw new Error('Booking must be COMPLETED to release funds');
    if (booking.escrow_released) throw new Error('Funds have already been released');

    const recipientCode = (booking.providers as any)?.paystack_recipient_code;
    const payment = (booking.payments as any)[0]; // Since 1 payment per booking in this model

    if (!recipientCode) throw new Error('Provider has no payout configuration');

    // 2. Deduct Platform Fee (e.g., 10%)
    const payoutAmount = Math.floor(payment.amount * 0.90 * 100);

    // 3. Initiate Transfer
    const transferResponse = await fetch('https://api.paystack.co/transfer', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${PAYSTACK_SECRET}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        source: 'balance',
        amount: payoutAmount,
        recipient: recipientCode,
        reason: `ServiceBridge Payout - Booking ${bookingId}`,
        reference: `escrow_${payment.paystack_reference}_${Date.now()}` // Unique deduplication
      }),
    });

    const transferData = await transferResponse.json();
    if (!transferData.status) throw new Error(`Transfer failed: ${transferData.message}`);

    // 4. Temporarily mark escrow as released pending Transfer Webhook success
    await supabase.from('bookings').update({ escrow_released: true }).eq('id', bookingId);

    return transferData.data;
  }
};

import { createClient } from '@/lib/supabase/client';
import { Provider } from '@/types';

const supabase = createClient();

export const providerService = {
  /**
   * Discovery: Find providers by category
   * Utilizes the GIN index on service_categories
   */
  async getProvidersByCategory(category: string, limit = 20, page = 1) {
    const from = (page - 1) * limit;
    const to = from + limit - 1;

    const { data, error, count } = await supabase
      .from('providers')
      .select('*, users!inner(name, location)', { count: 'exact' })
      .contains('service_categories', [category])
      .eq('verification_status', 'verified')
      .range(from, to)
      .order('avg_rating', { ascending: false });

    if (error) throw error;
    return { data: data as Provider[], count };
  },

  /**
   * Discovery: Filter providers by exact geographic location
   */
  async getProvidersByLocation(location: string, limit = 20, page = 1) {
    const from = (page - 1) * limit;
    const to = from + limit - 1;

    const { data, error, count } = await supabase
      .from('providers')
      .select('*, users!inner(name, location)', { count: 'exact' })
      .eq('service_area', location)
      .eq('verification_status', 'verified')
      .range(from, to)
      .order('avg_rating', { ascending: false });

    if (error) throw error;
    return { data: data as Provider[], count };
  },

  /**
   * Discovery: Get top-rated providers globally
   */
  async getTopRatedProviders(limit = 10) {
    const { data, error } = await supabase
      .from('providers')
      .select('*, users!inner(name)')
      .eq('verification_status', 'verified')
      .order('avg_rating', { ascending: false })
      .order('total_reviews', { ascending: false })
      .limit(limit);

    if (error) throw error;
    return data as Provider[];
  },

  /**
   * Discovery: Get fastest responding providers globally
   */
  async getFastestRespondingProviders(limit = 10) {
    const { data, error } = await supabase
      .from('providers')
      .select('*, users!inner(name)')
      .eq('verification_status', 'verified')
      .not('response_time', 'is', null)
      .order('response_time', { ascending: true })
      .limit(limit);

    if (error) throw error;
    return data as Provider[];
  },

  /**
   * Storage: Upload Portfolio Image (Max 10 images enforced via UI prior to this call)
   */
  async uploadPortfolioImage(providerId: string, file: File): Promise<string> {
    const fileExt = file.name.split('.').pop();
    const fileName = `${providerId}/${Math.random().toString(36).substring(2)}.${fileExt}`;

    const { data, error } = await supabase.storage
      .from('portfolio-images')
      .upload(fileName, file, { 
        upsert: false,
        cacheControl: '3600'
      });

    if (error) throw error;

    const { data: { publicUrl } } = supabase.storage
      .from('portfolio-images')
      .getPublicUrl(fileName);

    return publicUrl;
  }
};
